     1→/**
     2→ * TabNavigation Component
     3→ *
     4→ * Reusable tab navigation component for page-level navigation.
     5→ * Provides consistent styling and behavior across all tabbed pages.
     6→ *
     7→ * Features:
     8→ * - Consistent styling with semantic tokens
     9→ * - Keyboard navigation (Arrow keys, Home, End)
    10→ * - ARIA roles for accessibility
    11→ * - Icon + label support
    12→ * - Responsive wrapping
    13→ */
    14→
    15→import { useCallback, useRef, type KeyboardEvent } from 'react';
    16→import type { LucideIcon } from 'lucide-react';
    17→
    18→export interface Tab {
    19→  /** Unique identifier for the tab (used in URL query params) */
    20→  id: string;
    21→  /** Display label */
    22→  label: string;
    23→  /** Lucide icon component */
    24→  icon: LucideIcon;
    25→}
    26→
    27→interface TabNavigationProps {
    28→  /** Array of tab definitions */
    29→  tabs: Tab[];
    30→  /** Currently active tab ID */
    31→  activeTab: string;
    32→  /** Callback when tab changes */
    33→  onTabChange: (tabId: string) => void;
    34→  /** Additional CSS classes */
    35→  className?: string;
    36→  /** ARIA label for the tablist */
    37→  ariaLabel?: string;
    38→}
    39→
    40→/**
    41→ * TabNavigation provides consistent tab navigation across pages.
    42→ *
    43→ * @example
    44→ * const tabs: Tab[] = [
    45→ *   { id: 'calendar', label: 'Calendar', icon: Calendar },
    46→ *   { id: 'timer', label: 'Timer', icon: Timer },
    47→ * ];
    48→ *
    49→ * <TabNavigation
    50→ *   tabs={tabs}
    51→ *   activeTab={activeTab}
    52→ *   onTabChange={handleTabChange}
    53→ *   ariaLabel="Schedule navigation"
    54→ * />
    55→ */
    56→export function TabNavigation({
    57→  tabs,
    58→  activeTab,
    59→  onTabChange,
    60→  className = '',
    61→  ariaLabel = 'Page navigation',
    62→}: TabNavigationProps) {
    63→  const tabRefs = useRef<(HTMLButtonElement | null)[]>([]);
    64→
    65→  // Keyboard navigation handler
    66→  const handleKeyDown = useCallback(
    67→    (event: KeyboardEvent<HTMLButtonElement>, index: number) => {
    68→      let newIndex = index;
    69→
    70→      switch (event.key) {
    71→        case 'ArrowLeft':
    72→          newIndex = index > 0 ? index - 1 : tabs.length - 1;
    73→          break;
    74→        case 'ArrowRight':
    75→          newIndex = index < tabs.length - 1 ? index + 1 : 0;
    76→          break;
    77→        case 'Home':
    78→          newIndex = 0;
    79→          break;
    80→        case 'End':
    81→          newIndex = tabs.length - 1;
    82→          break;
    83→        default:
    84→          return;
    85→      }
    86→
    87→      event.preventDefault();
    88→      tabRefs.current[newIndex]?.focus();
    89→      onTabChange(tabs[newIndex].id);
    90→    },
    91→    [tabs, onTabChange]
    92→  );
    93→
    94→  return (
    95→    <div
    96→      className={`mb-6 border-b border-border-light dark:border-border-dark ${className}`}
    97→    >
    98→      <div
    99→        role="tablist"
   100→        aria-label={ariaLabel}
   101→        className="flex gap-1 flex-wrap"
   102→      >
   103→        {tabs.map((tab, index) => {
   104→          const Icon = tab.icon;
   105→          const isActive = activeTab === tab.id;
   106→
   107→          return (
   108→            <button
   109→              key={tab.id}
   110→              ref={(el) => {
   111→                tabRefs.current[index] = el;
   112→              }}
   113→              role="tab"
   114→              aria-selected={isActive}
   115→              aria-controls={`tabpanel-${tab.id}`}
   116→              id={`tab-${tab.id}`}
   117→              tabIndex={isActive ? 0 : -1}
   118→              onClick={() => onTabChange(tab.id)}
   119→              onKeyDown={(e) => handleKeyDown(e, index)}
   120→              className={`flex items-center gap-2 px-4 py-3 text-sm font-medium border-b-2 transition-colors ${
   121→                isActive
   122→                  ? 'border-accent-magenta dark:border-accent-cyan text-accent-magenta dark:text-accent-cyan'
   123→                  : 'border-transparent text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
   124→              }`}
   125→            >
   126→              <Icon className="w-4 h-4" aria-hidden="true" />
   127→              {tab.label}
   128→            </button>
   129→          );
   130→        })}
   131→      </div>
   132→    </div>
   133→  );
   134→}
   135→
   136→export default TabNavigation;
   137→

