   247→        setCategorizationError(result.error);
   248→      }
   249→    } catch (error) {
   250→      setIsCategorizing(false);
   251→      setCategorizationError(error instanceof Error ? error.message : 'Failed to load AI categorization');
   252→    }
   253→  }, [displayedLinks]);
