   268→  const handleRejectSuggestion = useCallback((linkId: string) => {
   269→    setPendingSuggestions((prev) => prev.filter((s) => s.linkId !== linkId));
   270→  }, []);
   271→
   272→  // Accept all suggestions
   273→  const handleAcceptAllSuggestions = useCallback(() => {
   274→    pendingSuggestions.forEach((suggestion) => {
