   276→        category: suggestion.category,
   277→        tags: suggestion.tags,
   278→      });
   279→    });
   280→    setPendingSuggestions([]);
   281→  }, [pendingSuggestions, updateLink]);
   282→
   283→  // Dismiss all suggestions
   284→  const handleDismissAllSuggestions = useCallback(() => {
   285→    setPendingSuggestions([]);
   286→  }, []);
