   292→  }, [getAllLinks]);
   293→
   294→  // Handle context menu
   295→  const handleContextMenu = useCallback((e: React.MouseEvent, link: Link) => {
   296→    e.preventDefault();
   297→    setContextMenu({ x: e.clientX, y: e.clientY, link });
   298→  }, []);
   299→
   300→  // Handle edit link
   301→  const handleEditLink = useCallback((link: Link) => {
   302→    setEditingLink(link);
   303→  }, []);
   304→
   305→  // Handle delete single link
   306→  const handleDeleteLink = useCallback((link: Link) => {
   307→    deleteLink(link.id);
