   315→    <PageContent page="links" variant="split-view">
   316→      {/* Collection Sidebar */}
   317→      <CollectionSidebar
   318→        isCollapsed={isSidebarCollapsed}
   319→        onToggleCollapse={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
   320→      />
   321→
   322→      {/* Main Content Area */}
   323→      <div className="flex-1 flex flex-col min-h-0 min-w-0 p-4 overflow-hidden">
   324→        {/* Stats Bar */}
   325→        <div className="flex items-center gap-4 mb-3 text-sm text-text-light-secondary dark:text-text-dark-secondary flex-shrink-0">
   326→          <span>{linkCount} links</span>
   327→          <span>•</span>
   328→          <span>{collectionCount} collections</span>
   329→          {selectedLinkIds.size > 0 && (
   330→            <>
   331→              <span>•</span>
   332→              <span className="text-accent-blue">{selectedLinkIds.size} selected</span>
   333→            </>
   334→          )}
   335→        </div>
